input.content:
{
  "version": "arkpilot-a2ui/v2",
  "kind": "semantic-ui-protocol",
  "appName": "平安扣 Pinankou",
  "targetDevice": {
    "widthVp": 1272,
    "heightVp": 2756,
    "contentMaxWidthVp": 420
  },
  "surfaces": [
    {
      "id": "home-page",
      "surfaceId": "home",
      "pageId": "home-page",
      "name": "首页 / 工作台",
      "route": "pages/Home",
      "tabId": "tab-home",
      "semanticTargets": [
        {
          "id": "home-header-title",
          "role": "assertion",
          "binding": "/appName"
        },
        {
          "id": "home-summary-pending-tasks",
          "role": "assertion",
          "binding": "/summary/pendingTasks"
        },
        {
          "id": "home-summary-pending-hazards",
          "role": "assertion",
          "binding": "/summary/pendingHazards"
        },
        {
          "id": "home-summary-inspection-rate",
          "role": "assertion",
          "binding": "/summary/inspectionRate"
        },
        {
          "id": "home-quick-report-hazard",
          "role": "action",
          "event": "navigate-to-report-hazard"
        },
        {
          "id": "home-quick-start-inspection",
          "role": "action",
          "event": "navigate-to-inspection"
        },
        {
          "id": "home-quick-emergency-contacts",
          "role": "action",
          "event": "navigate-to-emergency-contacts"
        },
        {
          "id": "home-quick-dashboard",
          "role": "action",
          "event": "navigate-to-dashboard"
        },
        {
          "id": "home-recent-activity-list",
          "role": "list",
          "binding": "/recentActivities",
          "itemIdPattern": "home-activity-{id}",
          "emptyStateId": "home-activity-empty-state"
        }
      ]
    },
    {
      "id": "safety-records-page",
      "surfaceId": "records",
      "pageId": "safety-records-page",
      "name": "安全事项",
      "route": "pages/SafetyRecords",
      "tabId": "tab-records",
      "semanticTargets": [
        {
          "id": "records-search-input",
          "role": "input",
          "binding": "/records/searchKeyword",
          "event": "search-records"
        },
        {
          "id": "records-filter-tab-all",
          "role": "action",
          "event": "filter-records-by-status-all"
        },
        {
          "id": "records-filter-tab-pending",
          "role": "action",
          "event": "filter-records-by-status-pending"
        },
        {
          "id": "records-filter-tab-done",
          "role": "action",
          "event": "filter-records-by-status-done"
        },
        {
          "id": "records-add-button",
          "role": "action",
          "event": "open-add-record-sheet"
        },
        {
          "id": "records-item-list",
          "role": "list",
          "binding": "/records/items",
          "itemIdPattern": "records-item-{id}",
          "emptyStateId": "records-empty-state"
        },
        {
          "id": "records-empty-state",
          "role": "assertion",
          "binding": "/records/isEmpty"
        }
      ]
    },
    {
      "id": "hazard-report-page",
      "surfaceId": "report",
      "pageId": "hazard-report-page",
      "name": "风险隐患上报",
      "route": "pages/HazardReport",
      "tabId": "tab-report",
      "semanticTargets": [
        {
          "id": "report-title-input",
          "role": "input",
          "binding": "/hazardForm/title",
          "event": "update-hazard-title"
        },
        {
          "id": "report-risk-level-picker",
          "role": "input",
          "binding": "/hazardForm/riskLevel",
          "event": "update-hazard-risk-level"
        },
        {
          "id": "report-hazard-type-picker",
          "role": "input",
          "binding": "/hazardForm/hazardType",
          "event": "update-hazard-type"
        },
        {
          "id": "report-location-input",
          "role": "input",
          "binding": "/hazardForm/location",
          "event": "update-hazard-location"
        },
        {
          "id": "report-location-refresh-button",
          "role": "action",
          "event": "refresh-hazard-location"
        },
        {
          "id": "report-description-input",
          "role": "input",
          "binding": "/hazardForm/description",
          "event": "update-hazard-description"
        },
        {
          "id": "report-photo-uploader",
          "role": "input",
          "binding": "/hazardForm/photos",
          "event": "update-hazard-photos"
        },
        {
          "id": "report-submit-button",
          "role": "action",
          "event": "submit-hazard-report"
        },
        {
          "id": "report-cancel-button",
          "role": "action",
          "event": "cancel-hazard-report"
        }
      ]
    },
    {
      "id": "inspection-checkin-page",
      "surfaceId": "inspection",
      "pageId": "inspection-checkin-page",
      "name": "巡检打卡",
      "route": "pages/InspectionCheckin",
      "tabId": "tab-inspection",
      "semanticTargets": [
        {
          "id": "inspection-progress-rate",
          "role": "assertion",
          "binding": "/inspection/progressRate"
        },
        {
          "id": "inspection-progress-text",
          "role": "assertion",
          "binding": "/inspection/progressText"
        },
        {
          "id": "inspection-filter-all",
          "role": "action",
          "event": "filter-inspection-all"
        },
        {
          "id": "inspection-filter-undone",
          "role": "action",
          "event": "filter-inspection-undone"
        },
        {
          "id": "inspection-filter-done",
          "role": "action",
          "event": "filter-inspection-done"
        },
        {
          "id": "inspection-point-list",
          "role": "list",
          "binding": "/inspection/points",
          "itemIdPattern": "inspection-point-{id}",
          "emptyStateId": "inspection-empty-state"
        },
        {
          "id": "inspection-scan-button",
          "role": "action",
          "event": "start-inspection-scan"
        },
        {
          "id": "inspection-batch-checkin-button",
          "role": "action",
          "event": "start-batch-checkin"
        }
      ]
    },
    {
      "id": "dashboard-page",
      "surfaceId": "dashboard",
      "pageId": "dashboard-page",
      "name": "统计看板",
      "route": "pages/Dashboard",
      "tabId": "tab-dashboard",
      "semanticTargets": [
        {
          "id": "dashboard-date-range-picker",
          "role": "input",
          "binding": "/dashboard/dateRange",
          "event": "update-dashboard-date-range"
        },
        {
          "id": "dashboard-kpi-total-hazards",
          "role": "assertion",
          "binding": "/dashboard/kpi/totalHazards"
        },
        {
          "id": "dashboard-kpi-pending-hazards",
          "role": "assertion",
          "binding": "/dashboard/kpi/pendingHazards"
        },
        {
          "id": "dashboard-kpi-fixed-hazards",
          "role": "assertion",
          "binding": "/dashboard/kpi/fixedHazards"
        },
        {
          "id": "dashboard-kpi-fix-rate",
          "role": "assertion",
          "binding": "/dashboard/kpi/fixRate"
        },
        {
          "id": "dashboard-kpi-inspection-rate",
          "role": "assertion",
          "binding": "/dashboard/kpi/inspectionRate"
        },
        {
          "id": "dashboard-trend-chart",
          "role": "assertion",
          "binding": "/dashboard/trendData"
        },
        {
          "id": "dashboard-risk-distribution-chart",
          "role": "assertion",
          "binding": "/dashboard/riskDistribution"
        },
        {
          "id": "dashboard-area-ranking-list",
          "role": "list",
          "binding": "/dashboard/areaRanking",
          "itemIdPattern": "dashboard-area-rank-{id}",
          "emptyStateId": "dashboard-area-ranking-empty-state"
        }
      ]
    },
    {
      "id": "emergency-contacts-page",
      "surfaceId": "contacts",
      "pageId": "emergency-contacts-page",
      "name": "应急联系人",
      "route": "pages/EmergencyContacts",
      "tabId": "tab-contacts",
      "semanticTargets": [
        {
          "id": "contacts-search-input",
          "role": "input",
          "binding": "/contacts/searchKeyword",
          "event": "search-contacts"
        },
        {
          "id": "contacts-add-button",
          "role": "action",
          "event": "open-add-contact-sheet"
        },
        {
          "id": "contacts-group-list",
          "role": "list",
          "binding": "/contacts/groups",
          "itemIdPattern": "contacts-group-{id}",
          "emptyStateId": "contacts-empty-state"
        },
        {
          "id": "contacts-empty-state",
          "role": "assertion",
          "binding": "/contacts/isEmpty"
        }
      ]
    },
    {
      "id": "record-detail-page",
      "surfaceId": "record-detail",
      "pageId": "record-detail-page",
      "name": "安全事项详情",
      "route": "pages/RecordDetail",
      "semanticTargets": [
        {
          "id": "record-detail-title",
          "role": "assertion",
          "binding": "/record/title"
        },
        {
          "id": "record-detail-status",
          "role": "assertion",
          "binding": "/record/status"
        },
        {
          "id": "record-detail-edit-button",
          "role": "action",
          "event": "open-edit-record"
        },
        {
          "id": "record-detail-delete-button",
          "role": "action",
          "event": "delete-record"
        },
        {
          "id": "record-detail-status-toggle",
          "role": "action",
          "event": "toggle-record-status"
        }
      ]
    },
    {
      "id": "hazard-detail-page",
      "surfaceId": "hazard-detail",
      "pageId": "hazard-detail-page",
      "name": "隐患详情",
      "route": "pages/HazardDetail",
      "semanticTargets": [
        {
          "id": "hazard-detail-title",
          "role": "assertion",
          "binding": "/hazard/title"
        },
        {
          "id": "hazard-detail-risk-level",
          "role": "assertion",
          "binding": "/hazard/riskLevel"
        },
        {
          "id": "hazard-detail-status",
          "role": "assertion",
          "binding": "/hazard/status"
        },
        {
          "id": "hazard-detail-assign-button",
          "role": "action",
          "event": "open-assign-hazard"
        },
        {
          "id": "hazard-detail-update-progress-button",
          "role": "action",
          "event": "open-update-hazard-progress"
        },
        {
          "id": "hazard-detail-accept-button",
          "role": "action",
          "event": "accept-hazard-fix"
        },
        {
          "id": "hazard-detail-reject-button",
          "role": "action",
          "event": "reject-hazard-fix"
        },
        {
          "id": "hazard-detail-timeline-list",
          "role": "list",
          "binding": "/hazard/timeline",
          "itemIdPattern": "hazard-timeline-{id}",
          "emptyStateId": "hazard-timeline-empty-state"
        }
      ]
    },
    {
      "id": "inspection-point-detail-page",
      "surfaceId": "inspection-point-detail",
      "pageId": "inspection-point-detail-page",
      "name": "巡检点位详情",
      "route": "pages/InspectionPointDetail",
      "semanticTargets": [
        {
          "id": "inspection-point-detail-name",
          "role": "assertion",
          "binding": "/inspectionPoint/name"
        },
        {
          "id": "inspection-point-detail-status",
          "role": "assertion",
          "binding": "/inspectionPoint/status"
        },
        {
          "id": "inspection-point-detail-checkin-button",
          "role": "action",
          "event": "perform-inspection-checkin"
        },
        {
          "id": "inspection-point-detail-photo-uploader",
          "role": "input",
          "binding": "/inspectionPoint/photos",
          "event": "update-inspection-photos"
        },
        {
          "id": "inspection-point-detail-note-input",
          "role": "input",
          "binding": "/inspectionPoint/note",
          "event": "update-inspection-note"
        },
        {
          "id": "inspection-point-detail-history-list",
          "role": "list",
          "binding": "/inspectionPoint/history",
          "itemIdPattern": "inspection-point-history-{id}",
          "emptyStateId": "inspection-point-history-empty-state"
        }
      ]
    },
    {
      "id": "contact-detail-page",
      "surfaceId": "contact-detail",
      "pageId": "contact-detail-page",
      "name": "联系人详情",
      "route": "pages/ContactDetail",
      "semanticTargets": [
        {
          "id": "contact-detail-name",
          "role": "assertion",
          "binding": "/contact/name"
        },
        {
          "id": "contact-detail-phone",
          "role": "assertion",
          "binding": "/contact/phone"
        },
        {
          "id": "contact-detail-call-button",
          "role": "action",
          "event": "call-contact"
        },
        {
          "id": "contact-detail-copy-phone-button",
          "role": "action",
          "event": "copy-contact-phone"
        },
        {
          "id": "contact-detail-edit-button",
          "role": "action",
          "event": "open-edit-contact"
        },
        {
          "id": "contact-detail-delete-button",
          "role": "action",
          "event": "delete-contact"
        }
      ]
    },
    {
      "id": "profile-page",
      "surfaceId": "profile",
      "pageId": "profile-page",
      "name": "我的",
      "route": "pages/Profile",
      "semanticTargets": [
        {
          "id": "profile-avatar",
          "role": "assertion",
          "binding": "/profile/avatar"
        },
        {
          "id": "profile-name",
          "role": "assertion",
          "binding": "/profile/name"
        },
        {
          "id": "profile-role",
          "role": "assertion",
          "binding": "/profile/role"
        },
        {
          "id": "profile-settings-button",
          "role": "action",
          "event": "open-settings"
        },
        {
          "id": "profile-about-button",
          "role": "action",
          "event": "open-about"
        }
      ]
    }
  ],
  "events": [
    {
      "name": "navigate-to-report-hazard",
      "description": "从首页快捷入口跳转到风险隐患上报"
    },
    {
      "name": "navigate-to-inspection",
      "description": "从首页快捷入口跳转到巡检打卡"
    },
    {
      "name": "navigate-to-emergency-contacts",
      "description": "从首页快捷入口跳转到应急联系人"
    },
    {
      "name": "navigate-to-dashboard",
      "description": "从首页快捷入口跳转到统计看板"
    },
    {
      "name": "search-records",
      "description": "搜索安全事项"
    },
    {
      "name": "filter-records-by-status-all",
      "description": "筛选全部安全事项"
    },
    {
      "name": "filter-records-by-status-pending",
      "description": "筛选待处理安全事项"
    },
    {
      "name": "filter-records-by-status-done",
      "description": "筛选已完成安全事项"
    },
    {
      "name": "open-add-record-sheet",
      "description": "打开新增安全事项表单"
    },
    {
      "name": "update-hazard-title",
      "description": "更新隐患标题"
    },
    {
      "name": "update-hazard-risk-level",
      "description": "更新风险等级"
    },
    {
      "name": "update-hazard-type",
      "description": "更新隐患类型"
    },
    {
      "name": "update-hazard-location",
      "description": "更新隐患位置"
    },
    {
      "name": "refresh-hazard-location",
      "description": "刷新定位"
    },
    {
      "name": "update-hazard-description",
      "description": "更新隐患描述"
    },
    {
      "name": "update-hazard-photos",
      "description": "更新隐患照片"
    },
    {
      "name": "submit-hazard-report",
      "description": "提交隐患上报"
    },
    {
      "name": "cancel-hazard-report",
      "description": "取消隐患上报"
    },
    {
      "name": "filter-inspection-all",
      "description": "筛选全部巡检点位"
    },
    {
      "name": "filter-inspection-undone",
      "description": "筛选未打卡巡检点位"
    },
    {
      "name": "filter-inspection-done",
      "description": "筛选已打卡巡检点位"
    },
    {
      "name": "start-inspection-scan",
      "description": "开始扫码巡检"
    },
    {
      "name": "start-batch-checkin",
      "description": "开始批量打卡"
    },
    {
      "name": "update-dashboard-date-range",
      "description": "更新看板时间范围"
    },
    {
      "name": "search-contacts",
      "description": "搜索应急联系人"
    },
    {
      "name": "open-add-contact-sheet",
      "description": "打开新增联系人表单"
    },
    {
      "name": "open-edit-record",
      "description": "打开编辑安全事项"
    },
    {
      "name": "delete-record",
      "description": "删除安全事项"
    },
    {
      "name": "toggle-record-status",
      "description": "切换安全事项状态"
    },
    {
      "name": "open-assign-hazard",
      "description": "打开隐患整改分配"
    },
    {
      "name": "open-update-hazard-progress",
      "description": "打开更新隐患进度"
    },
    {
      "name": "accept-hazard-fix",
      "description": "验收通过隐患整改"
    },
    {
      "name": "reject-hazard-fix",
      "description": "驳回隐患整改"
    },
    {
      "name": "perform-inspection-checkin",
      "description": "执行巡检打卡"
    },
    {
      "name": "update-inspection-photos",
      "description": "更新巡检照片"
    },
    {
      "name": "update-inspection-note",
      "description": "更新巡检备注"
    },
    {
      "name": "call-contact",
      "description": "拨打联系人电话"
    },
    {
      "name": "copy-contact-phone",
      "description": "复制联系人电话"
    },
    {
      "name": "open-edit-contact",
      "description": "打开编辑联系人"
    },
    {
      "name": "delete-contact",
      "description": "删除联系人"
    },
    {
      "name": "open-settings",
      "description": "打开设置"
    },
    {
      "name": "open-about",
      "description": "打开关于页面"
    }
  ],
  "bindings": [
    {
      "path": "/summary/pendingTasks",
      "type": "number",
      "description": "首页今日待处理事项数"
    },
    {
      "path": "/summary/pendingHazards",
      "type": "number",
      "description": "首页待整改隐患数"
    },
    {
      "path": "/summary/inspectionRate",
      "type": "number",
      "description": "首页今日巡检完成率 0-100"
    },
    {
      "path": "/records/items",
      "type": "array",
      "description": "安全事项列表"
    },
    {
      "path": "/records/searchKeyword",
      "type": "string",
      "description": "安全事项搜索关键词"
    },
    {
      "path": "/records/isEmpty",
      "type": "boolean",
      "description": "安全事项列表是否为空"
    },
    {
      "path": "/hazardForm/title",
      "type": "string",
      "description": "隐患标题"
    },
    {
      "path": "/hazardForm/riskLevel",
      "type": "string",
      "description": "风险等级：critical|major|general|low"
    },
    {
      "path": "/hazardForm/hazardType",
      "type": "string",
      "description": "隐患类型"
    },
    {
      "path": "/hazardForm/location",
      "type": "string",
      "description": "隐患位置"
    },
    {
      "path": "/hazardForm/description",
      "type": "string",
      "description": "隐患描述"
    },
    {
      "path": "/hazardForm/photos",
      "type": "array",
      "description": "隐患照片列表"
    },
    {
      "path": "/inspection/points",
      "type": "array",
      "description": "巡检点位列表"
    },
    {
      "path": "/inspection/progressRate",
      "type": "number",
      "description": "巡检完成率 0-100"
    },
    {
      "path": "/inspection/progressText",
      "type": "string",
      "description": "巡检进度文本，如 8/12"
    },
    {
      "path": "/dashboard/kpi/totalHazards",
      "type": "number",
      "description": "隐患总数"
    },
    {
      "path": "/dashboard/kpi/pendingHazards",
      "type": "number",
      "description": "待整改隐患数"
    },
    {
      "path": "/dashboard/kpi/fixedHazards",
      "type": "number",
      "description": "已整改隐患数"
    },
    {
      "path": "/dashboard/kpi/fixRate",
      "type": "number",
      "description": "整改率 0-100"
    },
    {
      "path": "/dashboard/kpi/inspectionRate",
      "type": "number",
      "description": "巡检完成率 0-100"
    },
    {
      "path": "/dashboard/trendData",
      "type": "array",
      "description": "隐患趋势数据"
    },
    {
      "path": "/dashboard/riskDistribution",
      "type": "array",
      "description": "风险等级分布数据"
    },
    {
      "path": "/dashboard/areaRanking",
      "type": "array",
      "description": "区域隐患排名数据"
    },
    {
      "path": "/contacts/groups",
      "type": "array",
      "description": "联系人分组列表"
    },
    {
      "path": "/contacts/searchKeyword",
      "type": "string",
      "description": "联系人搜索关键词"
    },
    {
      "path": "/contacts/isEmpty",
      "type": "boolean",
      "description": "联系人列表是否为空"
    }
  ],
  "testTargets": [
    {
      "id": "home-quick-report-hazard",
      "action": "click",
      "expected": "跳转至风险隐患上报页面"
